CREATE OR REPLACE FUNCTION "public"."_profile_is_device_operator_in_group"("p_user_id" "uuid", "p_group_id" "uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.profiles p
    JOIN public.group_members gm ON gm.user_id = p.id
    WHERE p.id = p_user_id
      AND 'device_operator' = ANY(COALESCE(p.roles, ARRAY[p.role]))
      AND gm.group_id = p_group_id
      AND gm.membership_status = 'active'
  );
$$;

