CREATE OR REPLACE FUNCTION "public"."publish_bounty"("p_group_id" "uuid", "p_title" "text", "p_total_hours" integer, "p_hourly_rate" numeric, "p_completion_days" integer, "p_description" "text" DEFAULT NULL::"text", "p_points_per_hour" numeric DEFAULT 1, "p_assigned_operator_id" "uuid" DEFAULT NULL::"uuid", "p_party_demand_ids" "uuid"[] DEFAULT NULL::"uuid"[]) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_id uuid;
  v_pd uuid;
BEGIN
  IF NOT public.has_profile_role('admin') THEN
    RAISE EXCEPTION 'admin only';
  END IF;
  IF NOT public.policy_work_group_accessible(p_group_id) THEN
    RAISE EXCEPTION 'group not accessible';
  END IF;
  IF p_assigned_operator_id IS NULL THEN
    RAISE EXCEPTION 'assigned operator required';
  END IF;
  IF NOT public._profile_is_device_operator_in_group(p_assigned_operator_id, p_group_id) THEN
    RAISE EXCEPTION 'assigned operator must be active device_operator in this group';
  END IF;
  IF p_party_demand_ids IS NULL OR array_length(p_party_demand_ids, 1) IS NULL THEN
    RAISE EXCEPTION 'at least one party demand (device type) required';
  END IF;
  FOREACH v_pd IN ARRAY p_party_demand_ids LOOP
    IF NOT EXISTS (
      SELECT 1 FROM public.party_demands pd
      WHERE pd.id = v_pd AND pd.group_id = p_group_id
    ) THEN
      RAISE EXCEPTION 'party demand % not in group', v_pd;
    END IF;
  END LOOP;
  IF p_total_hours IS NULL OR p_total_hours <= 0 THEN
    RAISE EXCEPTION 'total_hours must be positive';
  END IF;
  IF p_completion_days NOT IN (1, 2, 3) THEN
    RAISE EXCEPTION 'completion_days must be 1, 2, or 3';
  END IF;
  IF p_points_per_hour IS NULL OR p_points_per_hour <= 0 THEN
    p_points_per_hour := 1;
  END IF;
  INSERT INTO public.bounties (
    group_id, title, description, total_hours, remaining_hours,
    hourly_rate, completion_days, points_per_hour, status, created_by, assigned_operator_id
  )
  VALUES (
    p_group_id,
    COALESCE(NULLIF(trim(p_title), ''), '悬赏单'),
    NULLIF(trim(p_description), ''),
    p_total_hours,
    p_total_hours,
    COALESCE(p_hourly_rate, 0),
    p_completion_days,
    p_points_per_hour,
    'open',
    auth.uid(),
    p_assigned_operator_id
  )
  RETURNING id INTO v_id;
  FOREACH v_pd IN ARRAY p_party_demand_ids LOOP
    INSERT INTO public.bounty_allowed_party_demands (bounty_id, party_demand_id)
    VALUES (v_id, v_pd)
    ON CONFLICT DO NOTHING;
  END LOOP;
  RETURN v_id;
END;
$$;

CREATE OR REPLACE FUNCTION "public"."register_device_data_hours"("p_device_id" "text", "p_registered_hours" numeric, "p_bounty_claim_id" "uuid" DEFAULT NULL::"uuid", "p_note" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_group uuid;
  v_owner uuid;
  v_id uuid;
BEGIN
  IF NOT public.has_profile_role('device_operator') THEN
    RAISE EXCEPTION 'device_operator only';
  END IF;
  IF p_registered_hours IS NULL OR p_registered_hours <= 0 THEN
    RAISE EXCEPTION 'hours must be positive';
  END IF;
  SELECT d.user_id INTO v_owner FROM public.devices d WHERE d.device_id = p_device_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'device not found';
  END IF;
  IF v_owner <> auth.uid() THEN
    RAISE EXCEPTION 'only owner device_operator can register hours';
  END IF;
  v_group := public.user_active_group_id();
  IF v_group IS NULL THEN
    RAISE EXCEPTION 'no active work group';
  END IF;
  IF p_bounty_claim_id IS NOT NULL THEN
    IF NOT EXISTS (
      SELECT 1 FROM public.bounty_claims c
      JOIN public.bounties b ON b.id = c.bounty_id
      WHERE c.id = p_bounty_claim_id AND b.group_id = v_group
    ) THEN
      RAISE EXCEPTION 'claim not in your group';
    END IF;
  END IF;
  INSERT INTO public.device_data_hour_logs (
    group_id, device_id, bounty_claim_id, registered_hours, registered_by, note
  )
  VALUES (
    v_group, p_device_id, p_bounty_claim_id,
    p_registered_hours, auth.uid(), NULLIF(trim(p_note), '')
  )
  RETURNING id INTO v_id;
  RETURN v_id;
END;
$$;

CREATE OR REPLACE FUNCTION "public"."revoke_device_assignment"("p_assignment_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_row public.device_executor_assignments;
BEGIN
  IF NOT public.has_profile_role('device_operator') THEN
    RAISE EXCEPTION 'device_operator only';
  END IF;
  SELECT * INTO v_row FROM public.device_executor_assignments WHERE id = p_assignment_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'assignment not found';
  END IF;
  IF v_row.assigned_by <> auth.uid() AND NOT public.has_profile_role('admin') THEN
    RAISE EXCEPTION 'only assigner can revoke';
  END IF;
  UPDATE public.device_executor_assignments
  SET status = 'revoked', revoked_at = now()
  WHERE id = p_assignment_id;
END;
$$;

CREATE OR REPLACE FUNCTION "public"."sync_scene_task_assignments"("p_group_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'not authenticated' USING ERRCODE = '28000';
  END IF;
  IF NOT public.policy_work_group_accessible(p_group_id) AND NOT public.has_profile_role('admin') THEN
    RAISE EXCEPTION 'forbidden' USING ERRCODE = '42501';
  END IF;

  DELETE FROM public.scene_task_assignments sta
  USING public.scene_tasks st
  WHERE sta.scene_task_id = st.id
    AND st.group_id = p_group_id
    AND st.status <> 'published';

  DELETE FROM public.scene_task_assignments sta
  USING public.scene_tasks st, public.party_demands d, public.scenario_positions p
  WHERE sta.scene_task_id = st.id
    AND sta.party_demand_id = d.id
    AND sta.scenario_position_id = p.id
    AND st.group_id = p_group_id
    AND st.status = 'published'
    AND NOT public.scene_categories_overlap(d.scene_categories, p.scene_categories);

  INSERT INTO public.scene_task_assignments (scene_task_id, scenario_position_id, party_demand_id, max_hours_cap)
  SELECT st.id, p.id, d.id, d.max_hours_per_scene
  FROM public.scene_tasks st
  CROSS JOIN public.party_demands d
  INNER JOIN public.scenario_positions p
    ON p.group_id = p_group_id
    AND (st.scenario_position_id IS NULL OR p.id = st.scenario_position_id)
  WHERE st.group_id = p_group_id
    AND st.status = 'published'
    AND d.group_id = p_group_id
    AND public.scene_categories_overlap(d.scene_categories, p.scene_categories)
  ON CONFLICT (scene_task_id, scenario_position_id, party_demand_id) DO NOTHING;

  UPDATE public.scene_task_assignments sta
  SET max_hours_cap = d.max_hours_per_scene
  FROM public.party_demands d, public.scene_tasks st
  WHERE sta.party_demand_id = d.id
    AND sta.scene_task_id = st.id
    AND st.group_id = p_group_id
    AND d.group_id = p_group_id;
END;
$$;

NOTIFY pgrst, 'reload schema';
